
/**
 * Chatbot Renderer Module - Dashboard Parity Edition
 */
const ChatbotRenderer = (() => {
    const LOGO_BASE64 = "data:image/png;base64,";


    const ICONS = {
        sparkles: `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/><path d="M5 3v4"/><path d="M19 17v4"/><path d="M3 5h4"/><path d="M17 19h4"/></svg>`,
        lightbulb: `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M15 14c.2-1 .7-1.7 1.5-2.5 1-.9 1.5-2.2 1.5-3.5A6 6 0 0 0 6 8c0 1 .5 2.2 1.5 3.1.7.7 1.3 1.5 1.5 2.4"/><path d="M9 18h6"/><path d="M10 22h4"/></svg>`,
        chart: `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="18" y1="20" x2="18" y2="10"/><line x1="12" y1="20" x2="12" y2="4"/><line x1="6" y1="20" x2="6" y2="14"/></svg>`,
        table: `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 3v18"/><rect width="18" height="18" x="3" y="3" rx="2"/><path d="M3 9h18"/><path d="M3 15h18"/></svg>`,
        database: `<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><ellipse cx="12" cy="5" rx="9" ry="3"/><path d="M3 5V19A9 3 0 0 0 21 19V5"/><path d="M3 12A9 3 0 0 0 21 12"/></svg>`,
        export: `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" x2="12" y1="15" y2="3"/></svg>`,
        download: `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M14.5 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V7.5L14.5 2z"/><polyline points="14 2 14 8 20 8"/><path d="M12 18v-6"/><path d="m9 15 3 3 3-3"/></svg>`
    };

    const renderActions = (data) => {
        // Only show actions when there is real data to export/download
        const hasTableData = data.data?.data?.length > 0;
        const hasKPIs = data.kpis?.length > 0;
        const hasVisualizations = data.visualizations?.length > 0;

        if (!hasTableData && !hasKPIs && !hasVisualizations) {
            return ''; // greeting / text-only response — hide the button
        }

        const time = data.execution_metadata?.total_time ? `${data.execution_metadata.total_time.toFixed(2)} s` : '';
        const rows = data.data?.row_count ? `${data.data.row_count} rows` : '';

        return `
            <div class="zq-card" style="display: flex; align-items: center; justify-content: space-between; padding: 10px 16px; margin-top: 4px;">
                <div style="display: flex; gap: 12px; font-size: 11px; color: #64748b; font-weight: 500;">
                    ${rows ? `<span style="color: #475569; font-weight: 600;">${rows}</span>` : ''}
                    ${time ? `<span style="display: flex; align-items: center; gap: 4px;"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>${time}</span>` : ''}
                </div>
                <button class="zq-action-btn zq-download-btn" style="margin: 0; background: #f8fafc; border-color: #e2e8f0; padding: 5px 12px;">
                    ${ICONS.download} Download Report
                </button>
            </div>
        `;
    };


    const renderReportHtml = (data) => {
        const dateStr = new Date().toLocaleString();
        const summary = data.summary || data.execution_metadata?.ai_summary || data.answer || 'No summary available.';
        const insights = data.insights || data.execution_metadata?.insights || [];
        const kpis = data.kpis || [];
        const tableData = (data.data && data.data.data) ? data.data.data : [];
        const tableColumns = (data.data && data.data.columns) ? data.data.columns : [];

        return `
            <div id="zq-report-container">
                <div class="zq-report-header">
                    <div>
                        <h1 class="zq-report-title">Data Analysis Report</h1>
                        <div class="zq-report-meta">Generated on ${dateStr}</div>
                    </div>
                    <div style="text-align: right">
                        <div style="font-weight: 700; color: #4f46e5; font-size: 18px;">ZeroQueries</div>
                        <div style="font-size: 10px; color: #94a3b8; text-transform: uppercase; letter-spacing: 1px;">Intelligent Analytics</div>
                    </div>
                </div>

                <div class="zq-report-section">
                    <h2 class="zq-report-section-title">${ICONS.sparkles} Executive Summary</h2>
                    <div class="zq-report-card">
                        <p style="margin: 0; line-height: 1.6; color: #334155;">${summary}</p>
                    </div>
                </div>

                ${kpis.length ? `
                <div class="zq-report-section">
                    <h2 class="zq-report-section-title">${ICONS.chart} Key Performance Indicators</h2>
                    <div class="zq-report-grid">
                        ${kpis.map(kpi => `
                            <div class="zq-report-card">
                                <div style="font-size: 11px; font-weight: 600; color: #64748b; text-transform: uppercase; margin-bottom: 8px;">${kpi.name || kpi.label || ''}</div>
                                <div style="font-size: 24px; font-weight: 700; color: #0f172a;">${kpi.value}</div>
                            </div>
                        `).join('')}
                    </div>
                </div>
                ` : ''}

                ${insights.length ? `
                <div class="zq-report-section">
                    <h2 class="zq-report-section-title">${ICONS.lightbulb} Strategic Insights</h2>
                    <div class="zq-report-card">
                        ${insights.map(insight => {
            const title = typeof insight === 'object' && insight.title ? `<div style="font-weight: 600; font-size: 13px; color: #0f172a; margin-bottom: 2px;">${insight.title}</div>` : '';
            const desc = typeof insight === 'object' ? (insight.description || String(insight)) : insight;
            return `
                                <div style="display: flex; gap: 12px; margin-bottom: 12px;">
                                    <div style="width: 6px; height: 6px; border-radius: 50%; background: #4f46e5; margin-top: 6px; flex-shrink: 0;"></div>
                                    <div style="flex: 1;">
                                        ${title}
                                        <div style="font-size: 14px; color: #334155; line-height: 1.5;">${desc}</div>
                                    </div>
                                </div>
                            `;
        }).join('')}
                    </div>
                </div>
                ` : ''}

                ${tableData.length ? `
                <div class="zq-report-section">
                    <h2 class="zq-report-section-title">${ICONS.table} Data Detail</h2>
                    <div style="border: 1px solid #e2e8f0; border-radius: 8px; overflow: hidden;">
                        <table style="width: 100%; border-collapse: collapse; font-size: 11px;">
                            <thead>
                                <tr style="background: #f8fafc;">
                                    ${tableColumns.map(col => {
            const label = typeof col === 'string' ? col.replace(/_/g, ' ').toUpperCase() : (col.name || col.key || '');
            return `<th style="text-align: left; padding: 10px; border-bottom: 1px solid #e2e8f0; color: #64748b;">${label}</th>`;
        }).join('')}
                                </tr>
                            </thead>
                            <tbody>
                                ${tableData.slice(0, 50).map(row => `
                                    <tr>
                                        ${tableColumns.map(col => {
            const key = typeof col === 'string' ? col : (col.key || col.name);
            return `<td style="padding: 10px; border-bottom: 1px solid #f1f5f9; color: #334155;">${row[key] === null || row[key] === undefined ? '—' : row[key]}</td>`;
        }).join('')}
                                    </tr>
                                `).join('')}
                            </tbody>
                        </table>
                        ${tableData.length > 50 ? `<div style="padding: 10px; text-align: center; font-size: 10px; color: #94a3b8; background: #f8fafc;">Showing first 50 rows. Export CSV for full data.</div>` : ''}
                    </div>
                </div>
                ` : ''}

                <div style="margin-top: 50px; padding-top: 20px; border-top: 1px solid #f1f5f9; text-align: center; color: #94a3b8; font-size: 10px;">
                    © ${new Date().getFullYear()} ZeroQueries AI. All rights reserved. Confidential and Proprietary.
                </div>
            </div>
        `;
    };

    const renderKPIs = (kpis) => {
        if (!kpis || !kpis.length) return '';
        return `
            <div class="zq-card">
                <div style="display: flex; gap: 10px; margin-bottom: 16px;">
                    <div class="zq-icon-box zq-icon-emerald" style="width: 32px; height: 32px;">${ICONS.chart}</div>
                    <div>
                        <div style="font-size: 14px; font-weight: 600; color: #0f172a;">Performance Widgets</div>
                        <div style="font-size: 12px; color: #64748b;">Key metrics from your data</div>
                    </div>
                </div>
                <div class="zq-kpi-grid">
                    ${kpis.map(kpi => {
            const val = Number(kpi.value);
            const isNum = !isNaN(val) && isFinite(val);
            const displayValue = isNum ? val.toLocaleString() : kpi.value;
            return `
                            <div class="zq-kpi-card">
                                <div class="zq-label">${kpi.name}</div>
                                <div class="zq-kpi-val">${displayValue || '—'}</div>
                                ${kpi.change_percentage ? `
                                    <div style="color: ${kpi.trend === 'up' ? '#10b981' : '#ef4444'}; font-size: 11px; font-weight: 700; margin-top: 4px; display: flex; align-items: center; gap: 4px;">
                                        ${kpi.trend === 'up' ? '▲' : '▼'} ${kpi.change_percentage}%
                                    </div>
                                ` : ''}
                            </div>
                        `;
        }).join('')}
                </div>
            </div>
        `;
    };

    const renderInsights = (insights) => {
        if (!insights || !insights.length) return '';
        return `
            <div style="margin-top: 12px; background: #f8fafc; border: 1px solid #e2e8f0; border-radius: 8px; padding: 12px;">
                <div style="display: flex; align-items: center; gap: 8px; margin-bottom: 12px; color: #1e293b; font-weight: 600; font-size: 14px;">
                    <span style="color: #f59e0b">${ICONS.lightbulb}</span> Key Insights
                </div>
                <div style="display: flex; flex-direction: column; gap: 12px; padding-left: 12px;">
                    ${insights.map(insight => {
            const title = typeof insight === 'object' && insight.title ? `<div style="font-weight: 600; font-size: 13px; color: #0f172a;">${insight.title}</div>` : '';
            const desc = `<div style="font-size: 12px; color: #475569; line-height: 1.5;">${typeof insight === 'object' ? (insight.description || String(insight)) : insight}</div>`;
            return `
                            <div class="zq-insight-item">
                                <div class="zq-insight-dot"></div>
                                <div style="flex: 1;">${title}${desc}</div>
                            </div>
                        `;
        }).join('')}
                </div>
            </div>
        `;
    };

    const renderTable = (data) => {
        if (!data || !data.columns || !data.data || !data.data.length) return '';
        const columns = data.columns;
        const allData = data.data;
        const id = 'zq-table-' + Math.random().toString(36).substr(2, 9);

        return `
            <div class="zq-card">
                <div style="display: flex; align-items: center; justify-content: space-between; margin-bottom: 12px;">
                    <div style="display: flex; align-items: center; gap: 8px;">
                        <span style="color: #64748b;">${ICONS.table}</span>
                        <span style="font-weight: 600; font-size: 14px; color: #1e293b;">Data Table</span>
                    </div>
                    <button class="zq-action-btn zq-export-btn" title="Export CSV" style="margin: 0; padding: 4px 10px; background: #f8fafc;">
                        ${ICONS.export} Export
                    </button>
                </div>
                <div class="zq-table-container">
                    <table class="zq-table" id="${id}">
                        <thead>
                            <tr>${columns.map(col => `<th>${col.replace(/_/g, ' ').toUpperCase()}</th>`).join('')}</tr>
                        </thead>
                        <tbody>
                            ${allData.map((row, index) => `
                                <tr class="${index >= 10 ? 'zq-row-hidden' : ''}" style="${index >= 10 ? 'display: none;' : ''}">
                                    ${columns.map(col => {
            const key = typeof col === 'string' ? col : (col.key || col.name);
            return `<td>${row[key] === null || row[key] === undefined ? '—' : row[key]}</td>`;
        }).join('')}
                                </tr>
                            `).join('')}
                        </tbody>
                    </table>
                    ${allData.length > 10 ? `
                        <div class="zq-table-footer" onclick="
                            const table = document.getElementById('${id}');
                            const hiddenRows = table.querySelectorAll('.zq-row-hidden');
                            hiddenRows.forEach(row => row.style.display = 'table-row');
                            this.style.display = 'none';
                        " style="padding: 10px; text-align: center; font-size: 11px; color: #4f46e5; font-weight: 600; cursor: pointer; background: #f8fafc; border-top: 1px solid #e2e8f0; transition: background 0.2s;">
                            + ${allData.length - 10} more rows (Click to show all)
                        </div>
                    ` : ''}
                </div>
            </div>
        `;
    };

    const renderSQL = (sql) => {
        if (!sql) return '';
        const id = 'zq-sql-' + Math.random().toString(36).substr(2, 9);
        return `
            <div class="zq-sql-card" style="margin-top: 4px;">
                <div class="zq-sql-header" onclick="const body = this.nextElementSibling; const isOpen = body.style.display !== 'none'; body.style.display = isOpen ? 'none' : 'block'; this.querySelector('.zq-chevron').style.transform = isOpen ? 'rotate(0deg)' : 'rotate(180deg)';" >
                    <div style="display: flex; align-items: center; gap: 10px;">
                        <div class="zq-icon-box zq-icon-slate" style="width: 36px; height: 36px;">${ICONS.database}</div>
                        <div>
                            <div class="zq-label" style="margin: 0;">SQL Query</div>
                            <div style="font-size: 13px; font-weight: 500; color: #1e293b;">Click to view generated code</div>
                        </div>
                    </div>
                    <span class="zq-chevron" style="transition: transform 0.2s; color: #94a3b8; font-size: 10px;">▼</span>
                </div>
                <div class="zq-sql-body" style="display: none;">
                    <pre style="margin: 0; white-space: pre-wrap; overflow-x: auto; font-size: 11px; color: #334155;"><code>${sql}</code></pre>
                </div>
            </div>
        `;
    };

    const renderVisualizations = (visualizations) => {
        if (!visualizations || !visualizations.length) return '';
        return visualizations.map((viz) => {
            const chartId = 'zq-chart-' + Math.random().toString(36).substr(2, 9);
            const isPlotly = viz.plotly_json || viz.plotly_code;

            if (isPlotly) {
                const renderPlot = (attempts = 0) => {
                    const el = document.getElementById(chartId);
                    if (el && window.Plotly) {
                        const payload = viz.plotly_json || viz.plotly_code;
                        window.Plotly.newPlot(el, payload.data, {
                            ...payload.layout,
                            autosize: true,
                            margin: { t: 30, r: 20, b: 60, l: 60 },
                            font: { size: 10 },
                            paper_bgcolor: 'rgba(0,0,0,0)',
                            plot_bgcolor: 'rgba(0,0,0,0)'
                        }, { responsive: true, displayModeBar: false });
                    } else if (attempts < 10) {
                        setTimeout(() => renderPlot(attempts + 1), 200);
                    }
                };
                renderPlot();
            }

            return `
                <div class="zq-card">
                    <div style="margin-bottom: 8px;">
                        <div class="zq-label">Visualization</div>
                  
                    </div>
                    <div id="${chartId}" class="zq-viz-container" style="width: 100%; overflow: hidden; border-radius: 6px; background: #f8fafc;">
                        ${!isPlotly ? '<div class="zq-viz-fallback" style="display: flex; align-items: center; justify-content: center; color: #94a3b8; font-size: 11px;">Chart not available</div>' : ''}
                    </div>
                </div>
            `;
        }).join('');
    };
    const renderSuggestions = (suggestions) => {
        if (!suggestions || !suggestions.length) return '';
        // Handle both string array and object array [{question: '...'}]
        const validSuggestions = suggestions.map(s => {
            if (typeof s === 'string') return s;
            if (typeof s === 'object' && (s.question || s.text)) return s.question || s.text;
            return null;
        }).filter(s => s && s.trim().length > 0);

        if (validSuggestions.length === 0) return '';

        return `
            <div class="zq-card" style="padding: 12px 16px; margin-top: 4px;">
                <div style="font-size: 13px; font-weight: 600; color: #1e293b; margin-bottom: 8px;">Next Suggested Queries</div>
                <div style="display: flex; flex-direction: column; gap: 8px;">
                    ${validSuggestions.slice(0, 3).map((s, idx) => `
                        <button class="zq-suggestion-item" data-question="${s.replace(/"/g, '&quot;')}" style="display: block; text-align: left; background: none; border: none; padding: 0; margin: 0; font-size: 12px; font-weight: 500; color: #64748b; cursor: pointer; transition: color 0.2s;">
                            ${idx + 1}. <span style="text-decoration: none;">${s}</span>
                        </button>
                    `).join('')}
                </div>
            </div>
        `;
    };

    const formatMessage = (data) => {
        let html = '<div class="zq-ai-response">';

        // AI Summary Block
        const summary = data.execution_metadata?.ai_summary || data.answer || data.message || '';
        if (summary) {
            html += `
                <div class="zq-card">
                    <div style="display: flex; gap: 10px;">
                        <div class="zq-icon-box zq-icon-violet" style="width: 32px; height: 32px;">${ICONS.sparkles}</div>
                        <div style="flex: 1;">
                            <div class="zq-label">AI Summary</div>
                            <div style="font-size: 14px; color: #334155; line-height: 1.6; white-space: pre-wrap;">${summary}</div>
                        </div>
                    </div>
                    ${data.insights && data.insights.length ? renderInsights(data.insights) : ''}
                </div>
            `;
        }

        if (data.kpis && data.kpis.length) html += renderKPIs(data.kpis);
        if (data.visualizations && data.visualizations.length) html += renderVisualizations(data.visualizations);
        if (data.data && data.data.data && data.data.data.length) html += renderTable(data.data);
        if (data.data && data.data.query) html += renderSQL(data.data.query);

        // --- NEW: ACTIONS (Export/Report) ---
        html += renderActions(data);

        // Follow-up Suggestions (check multiple possible locations/naming)
        let suggestions = data.suggested_queries || data.suggested_questions || [];
        if ((!suggestions || !suggestions.length) && data.data) {
            suggestions = data.data.suggested_queries || data.data.suggested_questions || [];
        }

        if (suggestions && suggestions.length) {
            html += renderSuggestions(suggestions);
        }

        html += '</div>';
        return html;
    };

    return {
        formatMessage,
        renderReportHtml // Expose for PDF generation
    };
})();

// Ensure global availability
window.ChatbotRenderer = ChatbotRenderer;

if (typeof module !== 'undefined' && module.exports) {
    module.exports = ChatbotRenderer;
}

console.log('🎨 ZeroQueries ChatbotRenderer Loaded');
